import React from "react";
import { Link } from "react-router-dom";

export default function SignUp() {
  return (
    <div className="signup-div">
      <div className="signup-1">
        <span className="signup1-span1">Looks like you're new here!</span>
        <span className="signup1-span2">Sign up with your mobile number to get started</span>
        <img src="img/login-img.png" alt="login-img" />
      </div>
      <div>
        <form action="#">
          <input type="text" name="text" id="text" placeholder="Your Username" />
          <input type="email" name="email" id="email" placeholder="Your Email" />
          <input type="password" name="password" id="password" placeholder="Your Password" />
          <input type="password" name="cpassword" id="cpassword" placeholder="Confirm Password"/>
        </form>
      </div>
    </div>
  );
}
